#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        int result = 0;
        for (int i = 0; i < N; ++i) {
            int x;
            scanf("%d", &x);
            result ^= x;
        }
        printf("%d\n", result);
    }
    return 0;
}

